"""Скользящее среднее."""from __future__ import annotationsimport numpy as npfrom ..core.types import Signalfrom .base import BaseFilter, _check_odd_window, _reflect_padclass MovingAverageFilter(BaseFilter):    name = "Скользящее среднее"    description = "Линейный фильтр: среднее по окну нечётной длины."    params_schema = {        "window_length": {"type": "int", "default": 9,                          "min": 1, "max": 100_001,                          "label": "Размер окна (нечётное)"},    }    def _filter(self, x: np.ndarray, p: dict, signal: Signal) -> np.ndarray:        w = int(p["window_length"])        _check_odd_window("window_length", w, x.size)        if w == 1:            return x.copy()        half = w // 2        padded = _reflect_pad(x, half)        kernel = np.full(w, 1.0 / w, dtype=np.float64)        return np.convolve(padded, kernel, mode="valid")